mapper.select:
SELECT d.부서코드 deptCode, d.부서명 deptName, d.부서유형 deptType, d.상위부서코드 parentDeptCode, p.부서명 parentDeptName, d.지점명 branchName, d.사용여부 useStatus, d.순서 deptOrder FROM J_부서 d LEFT JOIN J_부서 p ON d.상위부서코드 = p.부서코드
d.사용여부 = '사용'
d.사용여부 = #{searchUseStatus}
AND d.부서명 LIKE '%' + #{searchDeptName} + '%'
AND d.부서유형 = #{searchDeptType}
ORDER BY d.순서 ASC, d.부서코드 ASC
